/** Nine different interpreters for Jam that differ in binding policy and cons evaluation policy.
  * The binding policy is either: call-by-value, call-by-name, or call-by-need.
  * The cons evaluation policy is either: call-by-value (eager), call-by-name (redundant lazy), or
  * call-by-need (efficient lazy).
  */

import java.io.IOException;
import java.io.Reader;
import java.util.HashMap;


/** The exception class for Jam run-time errors during program evaluation. */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** The exception class for type checking errors in Typed Jam. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Interpreter class supporting nine forms of evaluation for Jam programs.  These forms of evaluation differ in
  * binding policy and cons evaluation policy.
  * The binding policy is either: call-by-value, call-by-name, or call-by-need.
  * The cons evaluation policy is either: call-by-value (eager), call-by-name (redundant lazy), or
  * call-by-need (efficient lazy). */
class Interpreter {
  /** Parser to use. */
  Parser parser;  // initialized in constructors
  
  /** Parsed AST. */
  AST prog;       // initialized in constructors
  
  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = parser.parseAndCheck();
  }
  
  Interpreter(Parser p) {
    parser = p;
    prog = parser.parseAndCheck();
  }
  
  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = parser.parseAndCheck();
  }
  
  /* Interpreter API: the public methods of this Jam Interpreter */
  
  /** Parses and ValueValue interprets the input embeded in parser, returning the result. */
  public JamVal callByValue() { return prog.accept(valueValueVisitor); }
  
  /** Parses and NameValue interprets the input embeded in parser, returning the result. */
  public JamVal callByName() { return prog.accept(nameValueVisitor); }
  
  /** Parses and NeedValue interprets the input embeded in parser, returning the result. */
  public JamVal callByNeed() { return prog.accept(needValueVisitor); }
  
  /** Parses and ValueValue interprets the input embeded in parser, returning the result. */
  public JamVal valueValue() { return prog.accept(valueValueVisitor); }
  
  /** Parses and ValueName interprets the input embeded in parser, returning the result. */
  public JamVal valueName() { return prog.accept(valueNameVisitor); }
  
  /** Parses and ValueNeed interprets the input embeded in parser, returning the result. */
  public JamVal valueNeed() {return prog.accept(valueNeedVisitor); }
  
  /** Parses and NameValue interprets the input embeded in parser, returning the result.  */
  public JamVal nameValue() { return prog.accept(nameValueVisitor); }
  
  /** Parses and NameName interprets the input embeded in parser, returning the result. */
  public JamVal nameName() { return prog.accept(nameNameVisitor); }
  
  /** Parses and NameNeed interprets the input embeded in parser, returning the result. */
  public JamVal nameNeed() { return prog.accept(nameNeedVisitor); }
  
  /** Parses and NeedValue interprets the input embeded in parser, returning the result. */
  public JamVal needValue() { return prog.accept(needValueVisitor); }
  
  /** Parses and NeedName interprets the input embeded in parser, returning the result. */
  public JamVal needName() { return prog.accept(needNameVisitor); }
  
  /** Parses and NeedNeed interprets the input embeded in parser, returning the result. */
  public JamVal needNeed() { return prog.accept(needNeedVisitor); }

  /** Parses, type checks, and eagerly evaluates (call-by-value/eager) the input. */
  public JamVal eagerEval() {
    AST checked = checkTypes(prog);
    return checked.accept(valueValueVisitor);
  }

  /** Parses, type checks, and lazily evaluates (call-by-value/lazy) the input. */
  public JamVal lazyEval() {
    AST checked = checkTypes(prog);
    return checked.accept(valueNeedVisitor);
  }

  /** Type checks the given AST and returns it if it's well-typed.
    * Throws TypeException if type checking fails. */
  public AST checkTypes(AST ast) {
    new TypeCheckVisitor().checkExp(ast, new java.util.HashMap<String, Type>());
    return ast;
  }

  /* Interfaces that support different forms of variable binding and different forms of list construction */
  
  /** The interface supported by various binding evaluation policies: call-by-value, call-by-name, and call-by-need. */
  interface BindingPolicy {  // formerly called EvalPolicy
    
    /** Constructs the appropriate binding object for this, binding var to ast in the evaluator ev. */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
    
    /** Constructs the appropriate dummy binding object for this. */
    Binding newDummyBinding(Variable var);
  }
  
  /** Interface containing a factory to build the cons object specified by this ConsPolicy. */
  interface ConsPolicy {
    /** Constructs the appropriate cons given the arguments and corresponding EvalVisitor. */
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }
  
  /* Note: Binding is defined in the file ValuesTokens because the JamClosure class depends on it. */
  
  /** Class representing a binding in CBV evaluation. */ 
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() { 
      if (value == null) illegalForwardReference(var());
      return value; 
    }
    public void setBinding(Suspension s) { value = s.eval(); }  // immediate evaluation
    public String toString() { return "[" + var + ", " + value + "]"; }
  }
  
  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
  static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) { 
      super(v,null);
      susp = s;
    }
    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }
  
  /** Class representing a binding in CBNeed evaluation.  The inherited value field is used to hold the value
    * first computed by need .. */
  static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v,s); }
    public JamVal value() {
      if (value == null) {  // a legitimate JamVal CANNOT be null
        if (susp == null) illegalForwardReference(var());
        else {             // Force the suspension and cache its value
          value = susp.eval();
          susp = null;     // release susp object for GC!
        }
      }
      return value;
    }
    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }
  
  /** Helper method supporting Binding classes */
  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null, indicating an illegal forward reference");
  }
  
  /** Binding policy for call-by-value. */
  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) { return new ValueBinding(var, arg.accept(ev)); }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); } // null indicates still unbound
  };
  
  /** Binding policy for call-by-name. */
  static final BindingPolicy CALL_BY_NAME = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NameBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NameBinding(var, null); } // null indicates still unbound
  };
  
  /** Binding policy for call-by-need. */
  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); } // null indicates still unbound
  };
  
  
  /** A class representing an unevaluated expresssion (together with the corresponding evaluator). */
  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;  
    
    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }
    
    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }
    
    /** Evaluates this suspension. Only method in Suspension interface */
    public JamVal eval() { 
      // System.err.println("eval() called on the susp with AST = " + exp);
      return exp.accept(ev);
    } 
    
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }
  
  /** Class for a lazy cons structure. */
  static class JamLazyNameCons extends JamCons {
    /** Suspension for first */
    protected Suspension firstSusp;
    
    /** Suspension for rest */
    protected Suspension restSusp;
    
    public JamLazyNameCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp = new ConcreteSuspension(r, ev);
    }
    
    public JamVal first() { return firstSusp.eval(); }
    public JamList rest() { return checkList(restSusp.eval()); }
  }
  
  /** Class for a lazy cons with optimization. */
  static class JamLazyNeedCons extends JamLazyNameCons {
    
    public JamLazyNeedCons(AST f, AST r, EvalVisitor ev) { super(f, r, ev); }
    
    public JamVal first() {
      if (first == null) {
        first = firstSusp.eval();
        firstSusp = null;
      }
      return first;
    }
    
    public JamList rest() {
      if (rest == null) {
        rest = checkList(restSusp.eval());
        restSusp = null;
      }
      return (JamList)rest;
    }
  }
  
  /** Eager cons evaluation policy. Presumes that args has exactly 2 elements. */
  public static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) {
        return new JamCons(val0, (JamList)val1);
      }
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };
  
  /** Call-by-name lazy cons evaluation policy.  Presumes that args has exactly 2 elements. */
  public static final ConsPolicy LAZYNAME = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNameCons(args[0], args[1], ev); }
  };
  
  /** Call-by-need lazy cons evaluation policy.  Presumes that args has exactly 2 elements. */
  public static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };
  
  /** Value-value visitor. */
  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);
  
  /** Value-name visitor. */
  static final ASTVisitor<JamVal> valueNameVisitor = new EvalVisitor(CALL_BY_VALUE, LAZYNAME);
  
  /** Value-need visitor. */
  static final ASTVisitor<JamVal> valueNeedVisitor = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);
  
  /** Name-value visitor. */
  static final ASTVisitor<JamVal> nameValueVisitor = new EvalVisitor(CALL_BY_NAME, EAGER);
  
  /** Name-name visitor. */
  static final ASTVisitor<JamVal> nameNameVisitor = new EvalVisitor(CALL_BY_NAME, LAZYNAME);
  
  /** Name-need visitor. */
  static final ASTVisitor<JamVal> nameNeedVisitor = new EvalVisitor(CALL_BY_NAME, LAZYNEED);
  
  /** Need-value visitor. */
  static final ASTVisitor<JamVal> needValueVisitor = new EvalVisitor(CALL_BY_NEED, EAGER);
  
  /** Need-name visitor. */
  static final ASTVisitor<JamVal> needNameVisitor = new EvalVisitor(CALL_BY_NEED, LAZYNAME);
  
  /** Need-need visitor. */
  static final ASTVisitor<JamVal> needNeedVisitor = new EvalVisitor(CALL_BY_NEED, LAZYNEED);
  
  
  /** Primary visitor class for performing interpretation. */
  static class EvalVisitor implements ASTVisitor<JamVal> {
    
    /* Assumes that:
     *   OpTokens are unique
     *   Variable objects are unique: v1.name.equals(v.name) => v1 == v2
     *   Only objects used as boolean values are BoolConstant.TRUE and BoolConstant.FALSE
     * Hence, == can be used to compare Variable objects, OpTokens, and BoolConstants
     */
    
    /** Environment. */
    PureList<Binding> env;
    
    /** Policy to create bindings. */
    BindingPolicy bindingPolicy;
    
    /** Policy to create cons. */
    ConsPolicy consPolicy;
    
    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e;
      bindingPolicy = bp;
      consPolicy = cp;
    }
    
    public EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }
    
    /* EvalVisitor methods */
    
    /** Factory method that constructs a visitor similar to this with environment env. */
    public EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }
    
    /** Getter for env field. */
    public PureList<Binding> env() { return env; }
    
    /* methods of ASTVisitor<JamVal> interface */
    
    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i) { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }
    
    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) {
        throw new EvalException("variable " + v + " is unbound");
      }
      return match.value();
    }
    
    public JamVal forPrimFun(PrimFun f) { return f; }
    public JamVal forUnOpApp(UnOpApp u) { return u.rator().accept(new UnOpEvaluator(u.arg().accept(this))); }
    public JamVal forBinOpApp(BinOpApp b) { return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2())); }
    
    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun) 
        return ((JamFun)rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " appears at head of application " + a + " but it is not a valid function");
    }
    
    public JamVal forMap(Map m) { return new JamClosure(m, env); }
    
    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant))  throw new EvalException("non Boolean " + test + " used as test in if");
      if (test == BoolConstant.TRUE)  return i.conseq().accept(this);
      return i.alt().accept(this);
    }
    
    /** Evaluates a block expression by evaluating all expressions in sequence and returning the last value.
      * Blocks must contain at least one expression (enforced by parser). */
    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      int n = exps.length;
      if (n == 0) throw new EvalException("Block must contain at least one expression");
      JamVal result = null;
      for (int i = 0; i < n; i++) {
        result = exps[i].accept(this);
      }
      return result;
    }

    /* Recursive let semantics */
    public JamVal forLet(Let l) {
      
      /* Extract binding vars and exps (rhs's) from l */
      Variable[] vars = l.vars();
      AST[] exps = l.exps();
      int n = vars.length;
      
      /* Construct newEnv with dummy bindings for each variable in vars. */
      PureList<Binding> newEnv = env();
      Binding[] bindings = new Binding[n];
      for(int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(vars[i]);  // create appropriate form of dummy binding for var[i]
        newEnv = newEnv.cons(bindings[i]);                     // add new Binding to newEnv; it is shared so it can be updated
      }
      /* create new EvalVisitor instance with new environment (with dummy bindings for vars). */
      EvalVisitor newEV = newEvalVisitor(newEnv); 
      
      /* Fix up the dummy bindings in newEnv using exps as specified by binding policy using newEV (containing newEnv) */
      for(int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));  // modifies newEnv and hence newEV
      }
      return l.body().accept(newEV);
    }
    
    /* Inner classes */
    
    /** Evaluates the application of a function to an array of argument ASTs. A true inner class that accesses the enclosing 
      * EvalVisitor instance. The applied function may be a JamClosure or a PrimFun. */
    class FunEvaluator implements JamFunVisitor<JamVal> {
      /** Unevaluated arguments */
      AST[] args;
      
      FunEvaluator(AST[] asts) { args = asts; }
      
      /** The anonymous inner class that evaluates PrimFun applications.  The evaluation of arguments must be deferred
        * in the evaluation of lazy cons. As a result, the evalArgs() method is called in all of the forXXXX methods
        * except forCons.  Note: this anonymous inner class replaces the named static inner class StandardPrimFunVisior
        * in the solution to Assignment 2.   This revision was motivated by the fact that an anonymous inner class can 
        * access variables in the enclosing instance while a static inner instance class cannot.  This restriction is
        * very annoying when the static inner class is itself nested inside a true inner class; it cannot see the same
        * context as the inner class in which it is nested!
        * The evaluation of cons is special because it defers evaluating its arguments in the context of lazy 
        * evaluation. */
      
      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {
        
        /** Deferred evaluation of the args using the enclosing EvalVisitor. */
        private JamVal[] evalArgs() {
          int n = args.length;
          JamVal[] vals = new JamVal[n];
          for(int i = 0; i < n; i++) {
            vals[i] = args[i].accept(EvalVisitor.this);
          }
          return vals;
        }
        
        /** Throws an error.*/
        private void primFunError(String fn) {
          throw new EvalException("Primitive function `" + fn + "' applied to " + args.length + " arguments");
        }
        
        /** Evaluates an argument that has to be a Jam cons. */
        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) {
            return (JamCons)val;
          }
          throw new
            EvalException("Primitive function `" + fun + "' applied to argument " + val + " that is not a JamCons");
        }
        
        /* Visitor methods. */
        public JamVal forFunctionPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("function?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
        }
        
        public JamVal forNumberPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("number?");
          return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
        }
        
        public JamVal forListPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("list?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
        }
        
        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }
        
        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("null?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }

        public JamVal forRefPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("ref?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamRef);
        }

        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);   // Evaluation of args determined by consPolicy
        }
        
        public JamVal forArityPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("arity");
          if (!(vals[0] instanceof JamFun))  throw new EvalException("arity applied to argument " +  vals[0]);
          
          return ((JamFun)vals[0]).accept(new JamFunVisitor<IntConstant>() {
            public IntConstant forJamClosure(JamClosure jc) { return new IntConstant(jc.code().vars().length); }
            public IntConstant forPrimFun(PrimFun jpf) { return new IntConstant(jpf instanceof ConsPrim ? 2 : 1); }
          });
        }
        
        public JamVal forFirstPrim() { 
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first(); 
        }
        public JamVal forRestPrim() { 
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest(); 
        }
      };  // end of anonymous inner class primFunEvaluator
      
      /* Support for JamFunVisitor<JamVal> interface */
      
      /* Evaluates the closure application. */
      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        int n = args.length;
        Variable[] vars = map.vars();
        if (vars.length != n) {
          throw new EvalException("closure " + closure + " applied to " + n + " arguments");
        }
        /* Construct newEnv for JamClosure code using JamClosure env. */
        PureList<Binding> newEnv = closure.env();
        for(int i = 0; i < n; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(vars[i], args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }
      
      /* Evaluates the primFun application.  The arguments cannot be evaluated yet because cons may be lazy. */
      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }
    
    /** Evaluator for unary operators. Operand is already value (JamVal). */
    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      /** Value of the operand. */
      private JamVal val;
      
      UnOpEvaluator(JamVal jv) { val = jv; }
      
      /** Returns the value of the operand if it is an IntConstant; otherwise throws an exception. */
      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant)  return (IntConstant)val;
        throw new EvalException("Unary operator `" + op + "' applied to non-integer " + val);
      }
      
      /** Returns the value of the operand if it is a BoolConstant; otherwise throws an exception. */
      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant)  return (BoolConstant)val;
        throw new EvalException("Unary operator `" + op + "' applied to non-boolean " + val);
      }
      
      /** Returns the value of the operand if it is a JamRef; otherwise throws an exception. */
      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-ref " + val);
      }

      /* Visitor methods in UnOpVisitor<JamVal> interface */
      public JamVal forUnOpPlus() { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde() { return checkBoolean("~").not(); }
      public JamVal forOpBang() { return checkRef("!").value(); }
      public JamVal forOpRef() { return new JamRef(val); }
    }
    
    /** Evaluator for binary operators. A true inner class that references the enclosing EvalVisior. */
    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      /** Unevaluated arguments. */
      private AST arg1, arg2;
      
      BinOpEvaluator(AST a1, AST a2) {
        arg1 = a1;
        arg2 = a2;
      }
      
      /** Returns the value of arg if it is an IntConstant; otherwise throw an exception, */
      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant)  return (IntConstant)val;
        throw new EvalException("Binary operator `" + b + "' applied to non-integer " + val);
      }
      
      /** Returns the value of the argument if it is a BoolConstant, otherwise throw an exception, */
      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant)  return (BoolConstant)val;
        throw new EvalException("Binary operator `" + b + "' applied to non-boolean " + val);
      }
      
      /* Visitor methods */
      public JamVal forBinOpPlus() {
        return new IntConstant(evalIntegerArg(arg1,"+").value() + evalIntegerArg(arg2, "+").value());
      }
      
      public JamVal forBinOpMinus() {
        return new IntConstant(evalIntegerArg(arg1,"-").value() - evalIntegerArg(arg2, "-").value());
      }
      
      public JamVal forOpTimes() {
        return new IntConstant(evalIntegerArg(arg1,"*").value() * evalIntegerArg(arg2, "*").value());
      }
      
      public JamVal forOpDivide() {
        int divisor = evalIntegerArg(arg2, "/").value();
        if (divisor == 0) {
          throw new EvalException("Attempt to divide by zero");
        }
        return new IntConstant(evalIntegerArg(arg1,"/").value() / divisor);
      }
      
      public JamVal forOpEquals() {
        return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this)));
      }
      
      public JamVal forOpNotEquals() {
        return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this)));
      }
      
      public JamVal forOpLessThan() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value());
      }
      
      public JamVal forOpGreaterThan() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value());
      }
      
      public JamVal forOpLessThanEquals() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value());
      }
      
      public JamVal forOpGreaterThanEquals() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value());
      }
      
      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1, "&");
        if (b1 == BoolConstant.FALSE)  return BoolConstant.FALSE;
        return evalBooleanArg(arg2, "&");
      }
      
      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1, "|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2, "|");
      }

      public JamVal forOpGets() {
        JamVal val1 = arg1.accept(EvalVisitor.this);
        if (!(val1 instanceof JamRef))
          throw new EvalException("Binary operator `<-' applied to non-ref " + val1);
        JamVal val2 = arg2.accept(EvalVisitor.this);
        ((JamRef) val1).setValue(val2);
        return JamUnit.ONLY;
      }
    } // end of BinOpEvaluator class
  } // end of EvalVisitor class

  /* Type System for Typed Jam */

  /** Type interface for all Jam types. */
  interface Type {
    public String toString();
  }

  /** Type for int values. */
  static class IntType implements Type {
    public static final IntType ONLY = new IntType();
    private IntType() {}
    public String toString() { return "int"; }
  }

  /** Type for boolean values. */
  static class BoolType implements Type {
    public static final BoolType ONLY = new BoolType();
    private BoolType() {}
    public String toString() { return "bool"; }
  }

  /** Type for unit values. */
  static class UnitType implements Type {
    public static final UnitType ONLY = new UnitType();
    private UnitType() {}
    public String toString() { return "unit"; }
  }

  /** Type for list values with element type. */
  static class ListType implements Type {
    private Type elemType;
    ListType(Type et) { elemType = et; }
    public Type elemType() { return elemType; }
    public String toString() { return "list " + elemType; }
    public boolean equals(Object o) {
      if (!(o instanceof ListType)) return false;
      return elemType.equals(((ListType)o).elemType);
    }
  }

  /** Type for reference values with referenced type. */
  static class RefType implements Type {
    private Type elemType;
    RefType(Type et) { elemType = et; }
    public Type elemType() { return elemType; }
    public String toString() { return "ref " + elemType; }
    public boolean equals(Object o) {
      if (!(o instanceof RefType)) return false;
      return elemType.equals(((RefType)o).elemType);
    }
  }

  /** Type for function values. */
  static class FunType implements Type {
    private Type[] paramTypes;
    private Type resultType;
    FunType(Type[] pts, Type rt) { paramTypes = pts; resultType = rt; }
    public Type[] paramTypes() { return paramTypes; }
    public Type resultType() { return resultType; }
    public String toString() {
      StringBuilder sb = new StringBuilder("(");
      for (int i = 0; i < paramTypes.length; i++) {
        if (i > 0) sb.append(", ");
        sb.append(paramTypes[i]);
      }
      sb.append(" -> ").append(resultType).append(")");
      return sb.toString();
    }
    public boolean equals(Object o) {
      if (!(o instanceof FunType)) return false;
      FunType ft = (FunType)o;
      if (paramTypes.length != ft.paramTypes.length) return false;
      for (int i = 0; i < paramTypes.length; i++) {
        if (!paramTypes[i].equals(ft.paramTypes[i])) return false;
      }
      return resultType.equals(ft.resultType);
    }
  }

  /** Polymorphic type variable (like 'a in ML). */
  static class PolymorphicType implements Type {
    private String name;
    PolymorphicType(String n) { name = n; }
    public String name() { return name; }
    public String toString() { return "'" + name; }
    public boolean equals(Object o) {
      if (!(o instanceof PolymorphicType)) return false;
      return name.equals(((PolymorphicType)o).name);
    }
  }

  /** Type checking visitor. */
  static class TypeCheckVisitor {
    private java.util.Map<String, Type> typeEnv;

    /** Check an expression and return its type. */
    Type checkExp(AST exp, java.util.Map<String, Type> env) {
      this.typeEnv = env;
      return exp.accept(new ExpTypeChecker());
    }

    private class ExpTypeChecker implements ASTVisitor<Type> {
      public Type forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
      public Type forIntConstant(IntConstant i) { return IntType.ONLY; }
      public Type forEmptyConstant(EmptyConstant n) {
        // Return a polymorphic list type that can be any list type.
        // The actual element type is determined by context.
        return new ListType(new PolymorphicType("a"));
      }

      public Type forVariable(Variable v) {
        Type t = typeEnv.get(v.toString());
        if (t == null) throw new TypeException("Unbound variable: " + v);
        return t;
      }

      public Type forPrimFun(PrimFun f) {
        // PrimFuns need context-dependent typing. They should only appear in applications.
        // For now, we'll return a placeholder and handle them in forApp.
        // This allows them to appear syntactically but requires special handling in applications.
        return IntType.ONLY;  // placeholder - will be overridden in application context
      }

      public Type forUnOpApp(UnOpApp u) {
        Type argType = checkExp(u.arg(), typeEnv);
        UnOp op = u.rator();

        if (op == UnOpPlus.ONLY) {
          if (!(argType instanceof PolymorphicType) && !typeEq(argType, IntType.ONLY))
            throw new TypeException("Unary + expects int, got " + argType);
          return IntType.ONLY;
        }
        if (op == UnOpMinus.ONLY) {
          if (!(argType instanceof PolymorphicType) && !typeEq(argType, IntType.ONLY))
            throw new TypeException("Unary - expects int, got " + argType);
          return IntType.ONLY;
        }
        if (op == OpTilde.ONLY) {
          if (!(argType instanceof PolymorphicType) && !typeEq(argType, BoolType.ONLY))
            throw new TypeException("~ expects bool, got " + argType);
          return BoolType.ONLY;
        }
        if (op == OpBang.ONLY) {
          if (!(argType instanceof RefType) && !(argType instanceof PolymorphicType))
            throw new TypeException("! expects ref type, got " + argType);
          if (argType instanceof RefType)
            return ((RefType)argType).elemType();
          return new PolymorphicType("a");  // placeholder for polymorphic case
        }
        if (op == OpRef.ONLY) {
          return new RefType(argType);
        }
        throw new TypeException("Unknown unary operator: " + op);
      }

      public Type forBinOpApp(BinOpApp b) {
        Type arg1Type = checkExp(b.arg1(), typeEnv);
        Type arg2Type = checkExp(b.arg2(), typeEnv);
        BinOp op = b.rator();

        if (op == BinOpPlus.ONLY || op == BinOpMinus.ONLY || op == OpTimes.ONLY || op == OpDivide.ONLY) {
          if (!typeEq(arg1Type, IntType.ONLY))
            throw new TypeException("Binary " + op + " expects int operands, got " + arg1Type);
          if (!typeEq(arg2Type, IntType.ONLY))
            throw new TypeException("Binary " + op + " expects int operands, got " + arg2Type);
          return IntType.ONLY;
        }
        if (op == OpEquals.ONLY || op == OpNotEquals.ONLY) {
          // For = and !=, both operands must have the same type
          // Polymorphic types unify with any type
          if (!hasPolymorphicType(arg1Type) && !hasPolymorphicType(arg2Type)) {
            if (!typeEq(arg1Type, arg2Type))
              throw new TypeException("Comparison " + op + " requires same types, got " + arg1Type + " and " + arg2Type);
          }
          return BoolType.ONLY;
        }
        if (op == OpLessThan.ONLY || op == OpGreaterThan.ONLY ||
            op == OpLessThanEquals.ONLY || op == OpGreaterThanEquals.ONLY) {
          if (!typeEq(arg1Type, IntType.ONLY))
            throw new TypeException("Binary " + op + " expects int operands, got " + arg1Type);
          if (!typeEq(arg2Type, IntType.ONLY))
            throw new TypeException("Binary " + op + " expects int operands, got " + arg2Type);
          return BoolType.ONLY;
        }
        if (op == OpAnd.ONLY || op == OpOr.ONLY) {
          if (!typeEq(arg1Type, BoolType.ONLY))
            throw new TypeException("Binary " + op + " expects bool operands, got " + arg1Type);
          if (!typeEq(arg2Type, BoolType.ONLY))
            throw new TypeException("Binary " + op + " expects bool operands, got " + arg2Type);
          return BoolType.ONLY;
        }
        if (op == OpGets.ONLY) {
          if (!(arg1Type instanceof RefType))
            throw new TypeException("<- expects a ref type, got " + arg1Type);
          Type refElemType = ((RefType)arg1Type).elemType();
          if (!typeEq(refElemType, arg2Type))
            throw new TypeException("<- type mismatch: ref element type is " + refElemType + " but value is " + arg2Type);
          return UnitType.ONLY;
        }
        throw new TypeException("Unknown binary operator: " + op);
      }

      public Type forApp(App a) {
        AST rator = a.rator();
        AST[] args = a.args();

        // Special handling for primitive functions with polymorphic types
        if (rator instanceof PrimFun) {
          return typePrimApp((PrimFun) rator, args);
        }

        Type ratorType = checkExp(rator, typeEnv);
        if (!(ratorType instanceof FunType))
          throw new TypeException("Function application: rator has type " + ratorType + ", not a function type");
        FunType ft = (FunType) ratorType;
        Type[] paramTypes = ft.paramTypes();
        if (args.length != paramTypes.length)
          throw new TypeException("Function application: expected " + paramTypes.length + " arguments, got " + args.length);
        for (int i = 0; i < args.length; i++) {
          Type argType = checkExp(args[i], typeEnv);
          if (!typeEq(argType, paramTypes[i]))
            throw new TypeException("Function application: argument " + i + " has type " + argType + ", expected " + paramTypes[i]);
        }
        return ft.resultType();
      }

      /** Type check application of a primitive function with polymorphic type. */
      private Type typePrimApp(PrimFun prim, AST[] args) {
        // Handle each primitive function
        if (prim instanceof ConsPrim) {
          if (args.length != 2)
            throw new TypeException("cons expects 2 arguments, got " + args.length);
          Type elem = checkExp(args[0], typeEnv);
          Type list = checkExp(args[1], typeEnv);
          if (!(list instanceof ListType))
            throw new TypeException("cons second argument must be a list, got " + list);
          ListType lt = (ListType) list;
          // Check that element type matches list element type
          Type listElem = lt.elemType();
          // If list element type is concrete, check elem matches it
          if (!(listElem instanceof PolymorphicType)) {
            // List has concrete element type - elem must match
            if (elem instanceof PolymorphicType || !typeEq(elem, listElem)) {
              throw new TypeException("cons: element type " + elem + " does not match list element type " + listElem);
            }
          } else if (!(elem instanceof PolymorphicType)) {
            // Element is concrete, list is polymorphic - return list with concrete element type
            return new ListType(elem);
          }
          // Both polymorphic or element is concrete and matches - OK
          return list;
        }

        if (prim instanceof FirstPrim) {
          if (args.length != 1)
            throw new TypeException("first expects 1 argument, got " + args.length);
          Type list = checkExp(args[0], typeEnv);
          if (!(list instanceof ListType))
            throw new TypeException("first argument must be a list, got " + list);
          return ((ListType) list).elemType();
        }

        if (prim instanceof RestPrim) {
          if (args.length != 1)
            throw new TypeException("rest expects 1 argument, got " + args.length);
          Type list = checkExp(args[0], typeEnv);
          if (!(list instanceof ListType))
            throw new TypeException("rest argument must be a list, got " + list);
          return list;
        }

        if (prim instanceof EmptyPPrim) {
          if (args.length != 1)
            throw new TypeException("empty? expects 1 argument, got " + args.length);
          Type arg = checkExp(args[0], typeEnv);
          if (!(arg instanceof ListType))
            throw new TypeException("empty? argument must be a list, got " + arg);
          return BoolType.ONLY;
        }

        if (prim instanceof ConsPPrim) {
          if (args.length != 1)
            throw new TypeException("cons? expects 1 argument, got " + args.length);
          Type arg = checkExp(args[0], typeEnv);
          if (!(arg instanceof ListType))
            throw new TypeException("cons? argument must be a list, got " + arg);
          return BoolType.ONLY;
        }

        // For other prims (number?, function?, list?, ref?, arity), reject them
        throw new TypeException("Primitive function " + prim + " is not supported in typed Jam");
      }

      public Type forMap(Map m) {
        // Type-check the map body with parameters added to environment
        java.util.Map<String, Type> newEnv = new HashMap<String, Type>(typeEnv);
        Variable[] vars = m.vars();
        // For now, we can't determine parameter types from the AST since they were parsed and discarded
        // In a proper implementation, we'd store type annotations in the AST
        // For now, assume parameters have some generic type
        Type[] paramTypes = new Type[vars.length];
        for (int i = 0; i < vars.length; i++) {
          // We can't determine the type without storing it in the AST
          // For now, just add to environment with a placeholder
          paramTypes[i] = IntType.ONLY; // placeholder
          newEnv.put(vars[i].toString(), paramTypes[i]);
        }
        Type bodyType = checkExp(m.body(), newEnv);
        return new FunType(paramTypes, bodyType);
      }

      public Type forIf(If i) {
        Type testType = checkExp(i.test(), typeEnv);
        if (!typeEq(testType, BoolType.ONLY))
          throw new TypeException("if condition must be bool, got " + testType);
        Type conseqType = checkExp(i.conseq(), typeEnv);
        Type altType = checkExp(i.alt(), typeEnv);
        if (!typeEq(conseqType, altType))
          throw new TypeException("if branches have different types: " + conseqType + " vs " + altType);
        return conseqType;
      }

      public Type forLet(Let l) {
        // Type-check the let definitions and add variables to environment
        java.util.Map<String, Type> newEnv = new HashMap<String, Type>(typeEnv);
        Def[] defs = l.defs();
        for (Def def : defs) {
          Type expType = checkExp(def.rhs(), newEnv);
          Variable var = def.lhs();
          // For now, we can't extract the declared type from the AST since we parsed and discarded it
          // In a proper implementation, we'd check that expType matches the declared type
          // For now, just use the inferred type
          newEnv.put(var.toString(), expType);
        }
        // Type-check the body with the new environment
        return checkExp(l.body(), newEnv);
      }

      public Type forBlock(Block b) {
        Type resultType = null;
        for (AST exp : b.exps()) {
          resultType = checkExp(exp, typeEnv);
        }
        return resultType != null ? resultType : UnitType.ONLY;
      }
    }

    /** Check if a type contains any polymorphic type variables. */
    private boolean hasPolymorphicType(Type t) {
      if (t instanceof PolymorphicType) return true;
      if (t instanceof ListType) return hasPolymorphicType(((ListType)t).elemType);
      if (t instanceof RefType) return hasPolymorphicType(((RefType)t).elemType);
      if (t instanceof FunType) {
        FunType ft = (FunType) t;
        for (Type pt : ft.paramTypes()) {
          if (hasPolymorphicType(pt)) return true;
        }
        return hasPolymorphicType(ft.resultType());
      }
      return false;
    }

    /** Check if two types are equal. Polymorphic types unify with any type. */
    private boolean typeEq(Type t1, Type t2) {
      // Polymorphic types unify with any type
      if (t1 instanceof PolymorphicType || t2 instanceof PolymorphicType) return true;

      if (t1 == IntType.ONLY && t2 == IntType.ONLY) return true;
      if (t1 == BoolType.ONLY && t2 == BoolType.ONLY) return true;
      if (t1 == UnitType.ONLY && t2 == UnitType.ONLY) return true;
      if (t1 instanceof ListType && t2 instanceof ListType) {
        return typeEq(((ListType)t1).elemType, ((ListType)t2).elemType);
      }
      if (t1 instanceof RefType && t2 instanceof RefType) {
        return typeEq(((RefType)t1).elemType, ((RefType)t2).elemType);
      }
      if (t1 instanceof FunType && t2 instanceof FunType) {
        return t1.equals(t2);
      }
      return false;
    }
  }

} // end of Interpreter class

/** Jam lexer class for all assignments.              
  * Given a Lexer object, the next token in that input stream being processed by the Lexer is returned by the
  * readToken() method; it throws a ParseException (a form of RuntimeException) if it encounters a syntax error.  
  * Calling readToken() advances the cursor in the input stream to the next token.
  * 
  * The method peek() in the Lexer class has the same behavior as readToken() except for the fact that it does not
  * advance the cursor.
  */

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.IOException;
import java.io.Reader;
import java.io.StreamTokenizer;
import java.util.HashMap;

class Lexer extends StreamTokenizer {

  /* short names for StreamTokenizer codes */

  public static final int WORD = StreamTokenizer.TT_WORD; 
  public static final int NUMBER = StreamTokenizer.TT_NUMBER; 
  public static final int EOF = StreamTokenizer.TT_EOF; 
  public static final int EOL = StreamTokenizer.TT_EOL; 

  /* operator Tokens */

  // <unop>  ::= <sign> | ~   | ! 
  // <binop> ::= <sign> | "*" | / | = | != | < | > | <= | >= | & | "|" | <- 
  // <sign>  ::= "+" | -

  //  Note: there is no class distinction between <unop> and <binop> at 
  //  lexical level because of ambiguity; <sign> belongs to both

  public static final OpToken PLUS = OpToken.newBothOpToken(UnOpPlus.ONLY, BinOpPlus.ONLY); 
  public static final OpToken MINUS = OpToken.newBothOpToken(UnOpMinus.ONLY, BinOpMinus.ONLY);
  public static final OpToken TIMES = OpToken.newBinOpToken(OpTimes.ONLY);
  public static final OpToken DIVIDE = OpToken.newBinOpToken(OpDivide.ONLY);
  public static final OpToken EQUALS = OpToken.newBinOpToken(OpEquals.ONLY);
  public static final OpToken NOT_EQUALS = OpToken.newBinOpToken(OpNotEquals.ONLY);
  public static final OpToken LESS_THAN = OpToken.newBinOpToken(OpLessThan.ONLY);
  public static final OpToken GREATER_THAN = OpToken.newBinOpToken(OpGreaterThan.ONLY);
  public static final OpToken LESS_THAN_EQUALS = OpToken.newBinOpToken(OpLessThanEquals.ONLY);
  public static final OpToken GREATER_THAN_EQUALS = OpToken.newBinOpToken(OpGreaterThanEquals.ONLY);
  public static final OpToken NOT = OpToken.newUnOpToken(OpTilde.ONLY);
  public static final OpToken AND = OpToken.newBinOpToken(OpAnd.ONLY);
  public static final OpToken OR = OpToken.newBinOpToken(OpOr.ONLY);

  /* Used to support reference cells. */
  public static final OpToken BANG = OpToken.newUnOpToken(OpBang.ONLY);
  public static final OpToken GETS = OpToken.newBinOpToken(OpGets.ONLY);
  public static final OpToken REF = OpToken.newUnOpToken(OpRef.ONLY);

  /* Keywords */

  public static final KeyWord IF     = new KeyWord("if");
  public static final KeyWord THEN   = new KeyWord("then");
  public static final KeyWord ELSE   = new KeyWord("else");
  public static final KeyWord LET    = new KeyWord("let");
//  public static final KeyWord LETREC = new KeyWord("letrec");   // Used to support separate letrec construction
  public static final KeyWord IN     = new KeyWord("in");
  public static final KeyWord MAP    = new KeyWord("map");
  public static final KeyWord TO     = new KeyWord("to");
  public static final KeyWord BIND   = new KeyWord(":=");

  /* fields */

  /** The Reader from which this lexer reads. */
  public final Reader rdr;

  /* The wordtable for classifying words in token stream */
  public HashMap<String,Token>  wordTable = new HashMap<String,Token>();

  /** The buffer holding the next token in the intput stream; it is used to support the peek() operation, which cannot
    * be implemented using StreamTokenizer pushBack because some Tokens are composed of two StreamTokenizer tokens. */
  Token buffer;

  /* constructors */

  /** Constructs a Lexer for the specified inputStream */
  Lexer(Reader inputStream) {
    super(new BufferedReader(inputStream));
    rdr = inputStream;
    initLexer();
  }

  /** Constructor that uses a File as the input stream. */
  Lexer(String fileName) throws IOException {
    this(new FileReader(fileName));
  }

  /* Initializes lexer tables and the StreamTokenizer that the lexer extends */
  private void initLexer() {

    // configure StreamTokenizer portion of this
    resetSyntax();
    parseNumbers();
    ordinaryChar('-');
    slashSlashComments(true);
    wordChars('0', '9');
    wordChars('a', 'z');
    wordChars('A', 'Z');
    wordChars('_', '_');
    wordChars('?', '?');
    whitespaceChars(0, ' '); 

    // `+' `-' `*' `/' `~' `=' `<' `>' `&' `|' `:' `;' `,' '!'
    // `(' `)' `[' `]' are ordinary characters (self-delimiting)

    initWordTable();
    buffer = null;  // buffer initially empty
  }

  /** Resets the reader embedded in this lexer.  The same file may be scanned multiple times in tests. */
  public void reset() throws ParseException { 
    try { rdr.reset(); }
    catch(IOException e) { throw new ParseException(e); }
  }

  /** Reads tokens until next end-of-line */
  public void flush() throws IOException {
    eolIsSignificant(true);
    while (nextToken() != EOL) ; // eat tokens until EOL
    eolIsSignificant(false);
  }

  /** Returns the next token in the input stream without consuming it */
  public Token peek() { 
    if (buffer == null) buffer = readToken();
    return buffer;
  }

  /** Reads the next token as defined by StreamTokenizer in the input stream (consuming it). */
  private int getToken() {
    // synonymous with nextToken() except for throwing an unchecked 
    // ParseException instead of a checked IOException
    try {
      int tokenType = nextToken();
      return tokenType;
    } catch(IOException e) {
      throw new ParseException("IOException " + e + "thrown by nextToken()");
    }
  }

  /** Reads the next Token in the input stream (consuming it) */
  public Token readToken() {

    /* Uses getToken() to read next token and constructs the Token object representing that token.
     * NOTE: token representations for all Token classes except IntConstant are unique; a HashMap 
     * is used to avoid duplication.  Hence, == can safely be used to compare all Tokens except 
     * IntConstants for equality (assuming that code does not gratuitously create Tokens).  When the
     * stream is reduced to EOT, returns null instead of a Token.
     */

    if (buffer != null) {
      Token token = buffer;
      buffer = null;          // clear buffer
      return token;
    }

    int tokenType = getToken();

    switch (tokenType) {

      case NUMBER:
        int value = (int) nval;
        if (nval == (double) value) return new IntConstant(value);
        throw new ParseException("The number " + nval + " is not a 32 bit integer");
      case WORD:
        Token regToken = wordTable.get(sval);
        if (regToken == null) {
          // must be new variable name
          Variable newVar = new Variable(sval);
          wordTable.put(sval, newVar);
          return newVar;
        }
        return regToken;

      case EOF: return EndOfFile.ONLY;
      case '(': return LeftParen.ONLY;
      case ')': return RightParen.ONLY;
      case '[': return LeftBrack.ONLY;
      case ']': return RightBrack.ONLY;
      case '{': return LeftBrace.ONLY;
      case '}': return RightBrace.ONLY;
      case ',': return Comma.ONLY;
      case ';': return SemiColon.ONLY;

      case '+': return PLUS;  
      case '-': {
        // Check for -> (arrow for function types)
        int nextTokenType = getToken();
        if (nextTokenType == '>') {
          return Arrow.ONLY;  // -> token for function types
        }
        pushBack();
        return MINUS;
      }
      case '*': return TIMES;  
      case '/': return DIVIDE;  
      case '~': return NOT;  
      case '=': return EQUALS;

      case '<':
        tokenType = getToken();
        if (tokenType == '=') return LESS_THAN_EQUALS;
        if (tokenType == '-') return GETS;    // Used to support reference cells
        pushBack();
        return LESS_THAN; 

      case '>': 
        tokenType = getToken();
        if (tokenType == '=') return GREATER_THAN_EQUALS;  
        pushBack();
        return GREATER_THAN;

      case '!':
        tokenType = getToken();
        if (tokenType == '=') return NOT_EQUALS;
        pushBack();
        return BANG;  // Used to support reference cells 

      case '&': return AND;  
      case '|': return OR;  
      case ':': {
        tokenType = getToken();
        if (tokenType == '=') return BIND;   // ":=" is a keyword
        pushBack();
        return Colon.ONLY;  // ':' is used for type annotations
      }
      default:  
        throw new 
        ParseException("'" + ((char) tokenType) + "' is not a legal token");
    }
  }

  /** Initializes the table of Strings used to recognize Tokens */
  private void initWordTable() {
    // initialize wordTable

    // constants
    // <empty>  ::= empty
    // <bool>  ::= true | false

    wordTable.put("empty", EmptyConstant.ONLY);
    wordTable.put("true",  BoolConstant.TRUE);
    wordTable.put("false", BoolConstant.FALSE); 

    // Install primitive functions // (and unary operator named "ref" which is added in Assignment 4)
    // <prim>  ::= number? | function? | list? | empty? | cons? | ref? | arity | cons | first | rest 
    // Note: ref? is added in Assignment 4

    wordTable.put("number?",   NumberPPrim.ONLY);
    wordTable.put("function?", FunctionPPrim.ONLY);
    wordTable.put("list?",     ListPPrim.ONLY);
    wordTable.put("empty?",    EmptyPPrim.ONLY);
    wordTable.put("cons?",     ConsPPrim.ONLY);
    wordTable.put("ref?",      RefPPrim.ONLY);  // Supports the addition of reference cells
    wordTable.put("ref",       REF);            // Supports the addition of reference cells
    wordTable.put("arity",     ArityPrim.ONLY);  
    wordTable.put("cons",      ConsPrim.ONLY);
    wordTable.put("first",     FirstPrim.ONLY);
    wordTable.put("rest",      RestPrim.ONLY);


    // keywords: if then else let in map to := 
    wordTable.put("if",   Lexer.IF);
    wordTable.put("then", Lexer.THEN);
    wordTable.put("else", Lexer.ELSE);
    wordTable.put("let",  Lexer.LET);
    wordTable.put("in",   Lexer.IN);
    wordTable.put("map",  Lexer.MAP);
    wordTable.put("to",   Lexer.TO);    
  }
}

/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    } 
    finally {
      try { in.rdr.close(); } 
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);

    /* Invoke the CheckVisitor confirm prog does not contain free variables or parameter lists with duplicate names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
//    if (token == Lexer.LETREC) return parseLetRec();  // supports addition of letrec
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /*  Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      // including closing brace
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begin with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
//      System.err.println("exp updated to: " + exp);
      next = in.peek();
    }
//    System.err.println("parseTerm returning " + exp);
    return exp;
  }

  /** Parses:
    *   <term>     ::= { <unop> } <term> | <constant> | <factor> {( <exp-list> )}
    *   <constant> ::= <null> | <int> | <bool>
    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseTerm(Token token) {

    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op,"unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    if (token instanceof Constant) {
      // Check for type annotation on empty: empty : Type
      if (token == EmptyConstant.ONLY && in.peek() == Colon.ONLY) {
        in.readToken();  // consume the colon
        parseType();     // parse and skip the type
      }
      return (Constant) token;
    }

    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();  // remove next from input stream
      AST[] exps = parseArgs();  // including closing paren
      return new App(factor,exps);
    }
    return factor;
  }

  /** Parses:  <factor>   ::= <prim> | <variable> | ( <exp> )
    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseFactor(Token token) {

    if (token == LeftParen.ONLY) { 
      /* Parse a parenthesized expression */
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token,"`)'");
      return exp;
    }

    if (! (token instanceof PrimFun) && ! (token instanceof Variable))
      error(token,"constant, primitive, variable, or `('");

    // Term = Variable or PrimFun       
    return (Term) token;
  }      

  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
  private AST parseIf() {

    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1,"`then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2,"`else'");
    AST alt = parseExp();
    return new If(test,conseq,alt);
  }


  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */ 
  private AST parseLet() {
    Def[] defs = parseDefs(false); 
    // consumes `in'; false means rhs may be non Map
    AST body = parseExp();
    return new Let(defs,body);
  }

  /* Supports the parsing of separate 'letrec' construct */
//  /** Parses `letrec <prop-def-list> in <exp>' given that `letrec' has already been read. */
//  private AST parseLetRec() {
//    
//    Def[] defs = parseDefs(true);
//    // consumes `in'; true means each rhs must be a Map
//    AST body = parseExp();
//    return new LetRec(defs,body);
//  }

  /* Parses `map <id-list> to <exp>' given that `map' has already been read.
     Now supports typed variables: map x:int, y:int to ... */
  private AST parseMap() {

    Variable[] vars = parseTypedVars(); // consumes the delimiter `to'
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses a type. For now, just skip over the type tokens.
    * Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    */
  private void parseType() {
    Token t = in.peek();

    // Atomic types
    String typeStr = t.toString();
    if (typeStr.equals("unit") || typeStr.equals("int") || typeStr.equals("bool")) {
      in.readToken();  // consume the type keyword
      return;
    }

    // Composite types: list, ref, or function type
    if (typeStr.equals("list")) {
      in.readToken();  // consume 'list'
      parseType();  // recursively parse element type
      return;
    }

    if (typeStr.equals("ref")) {
      in.readToken();  // consume 'ref'
      parseType();  // recursively parse element type
      return;
    }

    if (t == LeftParen.ONLY) {
      in.readToken();  // consume '('
      parseTypeList();  // parse type arguments
      t = in.readToken();
      if (t != RightParen.ONLY) error(t, "`)'");
      return;
    }

    error(t, "type keyword");
  }

  /** Parses a comma-separated list of types followed by -> and return type. */
  private void parseTypeList() {
    // parse types separated by commas
    do {
      parseType();
      Token t = in.peek();
      if (t == Comma.ONLY) {
        in.readToken();  // consume comma
      } else {
        break;
      }
    } while (true);

    // parse arrow ->
    Token arrow = in.readToken();
    if (arrow == Arrow.ONLY) {
      // parse return type
      parseType();
    } else {
      error(arrow, "`->'");
    }
  }

  /** Parses typed variables for maps: id : type, id : type, ... to */
  private Variable[] parseTypedVars() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    Token t = in.readToken();
    if (t == Lexer.TO) return new Variable[0];

    do {
      if (!(t instanceof Variable)) error(t, "variable");
      vars.addLast((Variable)t);
      t = in.readToken();
      if (t == Colon.ONLY) {
        parseType();  // skip the type annotation
        t = in.readToken();
      }
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "`to' or `, '");
      // Comma found, read next variable
      t = in.readToken();
    } while (true);
    return (Variable[]) vars.toArray(new Variable[0]);
  }

  /** Parses `<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <empty> ::=
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list> 
    */
  private AST[] parseExps(Token separator, Token delim) {

    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume RightParen
      return new AST[0];
    }

    // next is still at front of input stream

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next,"`,' or `)'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY,RightParen.ONLY); }

  /** Parses <id-list> where
    *   <id-list>       ::= <empty> | <prop-id-list>
    *   <prop-id-list>  ::= <id> | <id> , <id-list> 
    *  NOTE: consumes `to' following <id-list>
    */
  private Variable[] parseVars() {

    LinkedList<Variable> vars = new LinkedList<Variable>();
    Token t = in.readToken();
    if (t == Lexer.TO) return new Variable[0];

    do {
      if (! (t instanceof Variable)) error(t,"variable");
      vars.addLast((Variable)t);
      t = in.readToken();
      if (t == Lexer.TO) break; 
      if (t != Comma.ONLY) error(t, "`to' or `, '");
      // Comma found, read next variable
      t = in.readToken();
    } while (true);
    return (Variable[]) vars.toArray(new Variable[0]);
  }

  /** Parses a proper list of definitions, more technically parses
    *   <prop-def-list> ::= <def> | <def> <def-list> 
    *   NOTE: consumes `in' following <prop-def-list> */

  private Def[] parseDefs(boolean forceMap) {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);        
      if (forceMap && (! (d.rhs() instanceof Map)))
        throw new ParseException("right hand side of definition `" + d + "' is not a map expression");
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses
    *   <id> : <type> := <exp> ;
    * or <id> := <exp> ;
    * which is <def> given that first token var has been read.
    */
  private Def parseDef(Token var) {

    if (! (var instanceof Variable)) error(var, "variable");
    Variable v = (Variable) var;

    Token key = in.readToken();

    // Handle optional type annotation
    if (key == Colon.ONLY) {
      parseType();  // skip the type annotation
      key = in.readToken();
    }

    if (key != Lexer.BIND) error (key,"`:='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi,"`;'");
    return new Def(v, exp);
  }

  private AST error(Token found, String expected) {
//    for (int i = 0; i < 10; i++) {
//      System.out.println(in.readToken());
//    }   
    throw new ParseException("Token `" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy "main" method that perhaps should be deleted. */
  public static void main(String[] args) throws IOException {
    // check for legal argument list 
    if (args.length == 0) {
//      System.out.println("Usage: java Parser <filename>");
      return;
    }
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
//    System.out.println("Parse tree is: " + prog);
  }
}

/* JamVal and Token Data Definitions */

import java.util.NoSuchElementException;
  
/** A data object representing a Jam value.
  * JamVal := IntConstant | BoolConstant | JamList | JamFun */
interface JamVal {
  <ResType> ResType accept(JamValVisitor<ResType> jvv);
}

/** A visitor for the JamVal type (Jam values).  */
interface JamValVisitor<ResType> {
  ResType forIntConstant(IntConstant ji);
  ResType forBoolConstant(BoolConstant jb);
  ResType forJamList(JamList jl);
  ResType forJamFun(JamFun jf);
  ResType forJamRef(JamRef jr);
  ResType forJamUnit(JamUnit ju);
}

/** JamVal classes */

/** A Jam integer constant, also used to represent an integer token for parsing.  */
class IntConstant implements Token, Constant, JamVal {
  private int value;
  
  IntConstant(int i) { value = i; }
  // duplicates can occur!
  
  public int value() { return value; }
  
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIntConstant(this); }
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forIntConstant(this); }
  /** redefines equals so that equal integers are recognized as equal */
  public boolean equals(Object other) {
    return (other != null && this.getClass() == other.getClass()) && 
      (value == ((IntConstant)other).value());
  }
  /** computes the obvious hashcode for this consistent with equals. */
  public int hashcode() { return value; }
  public String toString() { return String.valueOf(value); }
}

/** A Jam boolean constant, also used to represent a boolean token for parsing. */
class BoolConstant implements Token, Constant, JamVal {
  private boolean value;
  private BoolConstant(boolean b) { value = b; }
  
  /** Singleton pattern definitions. */
  public static final BoolConstant FALSE = new BoolConstant(false);
  public static final BoolConstant TRUE = new BoolConstant(true);
  
  /** A factory method that returns BoolConstant corresponding to b. It is atatic because
    * it does not depend on this. */
  public static BoolConstant toBoolConstant(boolean b) { 
    if (b) return TRUE; 
    else return FALSE;
  }
  
  public boolean value() { return value; }
  public BoolConstant not() { if (this == FALSE) return TRUE; else return FALSE; }
  
  public <ResType> ResType accept(ASTVisitor<ResType> av) { return av.forBoolConstant(this); }
  public <ResType> ResType accept(JamValVisitor<ResType> jv) { return jv.forBoolConstant(this); }
  public String toString() { return String.valueOf(value); }
}

/* Immutable List and Binding Classes */

/** Interface for all Pure Lists.
  * PureList<ElemType> := Empty<ElemType> | Cons<ElemType>
  */
interface PureList<ElemType> {
  abstract PureList<ElemType> cons(ElemType o);
  abstract PureList<ElemType> empty();
  abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);
    abstract boolean contains(ElemType e);
    abstract String toStringHelp();
  abstract PureList<ElemType> append(PureList<ElemType> addedElts);
}

/** The visitor interface for the type PureList<ElemType> */
interface PureListVisitor<ElemType, ResType> {
  ResType forEmpty(Empty<ElemType> e);
  ResType forCons(Cons<ElemType> c);
}

/** An abstract class that factors out code common to classes Empty<T> and Cons<T> */
abstract class PureListClass<ElemType> implements PureList<ElemType> {
  public PureList<ElemType> cons(ElemType o) { return new Cons<ElemType>(o,this); }
  public PureList<ElemType> empty() { return new Empty<ElemType>(); }
  public abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);  
  // preceding DICTATED BY BUG IN JSR-14
}

/** The empty PureList<T> class */
class Empty<ElemType> extends PureListClass<ElemType> {
  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forEmpty(this); }
  public PureList<ElemType> append(PureList<ElemType> addedElts) { return addedElts; }
  public boolean contains(ElemType e) { return false; }
  
  /** overrides inherited equals because Empty is not a singleton! */
  public boolean equals(Object other) { 
    return (other != null && other.getClass() == this.getClass());
  }
  
  public String toString() { return "()"; }
  public String toStringHelp() { return ""; }
}

/** The non-empty PureList<T> class */
class Cons<ElemType> extends PureListClass<ElemType> {
  ElemType first;
  PureList<ElemType> rest;
  Cons(ElemType f, PureList<ElemType> r) { first = f; rest = r; }
  
  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forCons(this); }
  public PureList<ElemType> append(PureList<ElemType> addedElts) { 
    return new Cons<ElemType>(first, rest.append(addedElts)); 
  }
  
  public ElemType first() { return first; }
  public PureList<ElemType> rest() { return rest; }
  public boolean contains(ElemType e) {
    if (first.equals(e)) return true;
    else return rest().contains(e);
  }
  
  /** Overrides inherited equals to perform structural equality testing. */
  public boolean equals(Object other) { 
    if (other == null || ! (other instanceof Cons)) return false;
    if (other == this) return true;
    Cons otherCons = (Cons) other;
    return first().equals(otherCons.first()) && rest().equals(otherCons.rest());
  }
  /** Overrides hash code in accord with equals. */
  public int hashCode() { return first().hashCode() + rest().hashCode(); }
  
  public String toString() { return "(" + first + rest.toStringHelp() + ")"; }
  public String toStringHelp() { return " " + first + rest.toStringHelp(); }
}

/** The Jam List class representing JamVals that are PureLists. 
  * JamList := JamEmpty | JamCons
  */
interface JamList extends PureList<JamVal>, JamVal {
  JamEmpty empty();
  JamCons cons(JamVal v);
  /** Helper method that returns the depth-bounded string representation of this list with a leading blank in front of
    * each element and no enclosing parentheses.  For lists longer than maxDepth, elipsis is printed instead of the 
    * elements. */
  String toStringHelp(int maxDepth);
}

/** A singleton class extending Empty<JamVal> representing the empty JamList. */
class JamEmpty extends Empty<JamVal> implements JamList {
  public static final JamEmpty ONLY = new JamEmpty();
  private JamEmpty() {}
  
  public JamEmpty empty() { return ONLY; }
  public JamCons cons(JamVal v) { return new JamCons(v, this); }
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forJamList(this); }
  
  public String toStringHelp(int maxDepth) { return ""; }
}

class JamCons extends Cons<JamVal> implements JamList {
  
  /** Maximum depth of printing the elements of a potentially lazy stream. */
  private static final int MAX_DEPTH = 1000;
  
  public JamCons(JamVal v, JamList vList) { super(v, vList); }
  
  /** Factory method that returns an empty list. */
  public JamEmpty empty() { return JamEmpty.ONLY; }
  
  /** Factory method that return a list consisting of cons(v, this). */
  public JamCons cons(JamVal v) { return new JamCons(v, this); }
  
  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forJamList(this); }
  public JamList rest() { return (JamList) super.rest(); }
  
  /** Returns val if val is a JamList. Otherwise it throws an EvalException. */
  public static JamList checkList(JamVal val) {
    if (val instanceof JamList)  return (JamList)val;
    throw new EvalException("The second argument to lazy cons is `" + val + "' which is not a list");
  }
  
  /* Depth-bounded printing method which must be defined at this level so that ordinary JamCons nodes appearing
   * within lazy lists are printed correctly. */
  
  /** Return the depth-bounded string representation of this. */
  public String toString() { return "(" + first() + rest().toStringHelp(MAX_DEPTH) + ")"; }
  
  /** Return the depth-bounded string representation for this with a leading blank but no enclosing parentheses. */
  public String toStringHelp(int maxDepth) {
    if (maxDepth == 0)  return " ...";
    return " " + first() + rest().toStringHelp(maxDepth - 1);
  }
}

/* Important List Utilities defined by visitors */

/** Interface for classes with a variable field (Variable and the various Binding classes). This interface permits
  * the generic LookupVisitor below to operate on any subclass of PureList<T> where T implements WithVariable. */
interface WithVariable {
  /** Accessor for the variable. */
  Variable var();
}

/** A generalized lookup visitor class that returns the element matching the embedded var in a 
  * PureList<Elemtype extends WithVariable>. If no match found, returns null. */
class LookupVisitor<ElemType extends WithVariable> implements PureListVisitor<ElemType, ElemType> {
  /** Variable to look up. */
  Variable var;
  
  // Invariant: the lexer guarantees that there is only one Variable instance for a given name enabling == testing
  
  LookupVisitor(Variable v) { var = v; }
  
  /** Case for empty lists. */
  public ElemType forEmpty(Empty<ElemType> e) { return null; }
  
  /** Case for non-empty lists. */
  public ElemType forCons(Cons<ElemType> c) {
    ElemType e = c.first();
    if (var == e.var()) return e;
    return c.rest().accept(this);
  }
}

/* Other JamVal classes */

/** The class representing a Jam function (closure or primitive function). 
  * JamFun := JamClosure | PrimFun
  */
abstract class JamFun implements JamVal {
  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamFun(this); }
  abstract public <ResType> ResType accept(JamFunVisitor<ResType> jfv);
}

/** The visitor interface for the JamFun type */
interface JamFunVisitor<ResType> {
  ResType forJamClosure(JamClosure c);
  ResType forPrimFun(PrimFun pf);
}

/** The Suspension interface for a potentially deferred JamVal. This interface is intentionally opaque. */
interface Suspension {
  JamVal eval();
}

/** The abstract Jam binding class required to define JamClosure.  Makes no commitment regarding when the RHSs of 
  * variable bindings are evaluated.  The setBinding method takes a Suspension as input; evaluation may be deferred. */
abstract class Binding implements WithVariable {
  Variable var;
  JamVal value;
  Binding(Variable v, JamVal jv) { 
    var = v; value = jv;
  }
  public Variable var() { return var; }
  
  /** Return the value of the binding which may require evaluation. */
  public JamVal value() { return value; }
  
  /** Sets the binding to the value of the specified by the Suspension s.  The Suspension s may be evaluated immediately
    * or delayed until value() is called depending on the Binding mechanism. */
  public abstract void setBinding(Suspension s);
}
 
/** The class representing a Jam Closure. */
class JamClosure extends JamFun {
  private Map code;
  private PureList<Binding> env;
  
  JamClosure(Map c, PureList<Binding> e) { code = c; env = e; }
  Map code() { return code; }
  PureList<Binding> env() { return env; }
  public <ResType> ResType accept(JamFunVisitor<ResType> jfv) { return jfv.forJamClosure(this); }
}

/** The class representing a Jam Primitive Function. 
  * PrimFun := FunctionPPrim | NumberPPrim | ListPPrim | ConsPPrim | EmptyPPrim | ArityPrim | ConsPrim | FirstPrim | RestPrim 
  */
abstract class PrimFun extends JamFun implements Token, Term {
  private String name;
  PrimFun(String n) { name = n; }
  public String name() { return name; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forPrimFun(this); }
  public <ResType> ResType accept(JamFunVisitor<ResType> v) { return v.forPrimFun(this); }
  abstract public <ResType> ResType accept(PrimFunVisitor<ResType> pfv);
  public String toString() { return name; }
}

